class Solution:
    def maximumNumberOfStringPairs(self, words):
        n = len(words)
        used = [False] * n
        count = 0
        for i in range(n):
            if used[i]:
                continue
            for j in range(i + 1, n):
                if used[j]:
                    continue
                if words[i] == words[j][::-1]:
                    count += 1
                    used[i] = True
                    used[j] = True
                    break
        return count

