var maximumNumberOfStringPairs = function(words) {
    const seen = new Set();
    let count = 0;
    for (const w of words) {
        const r = w.split('').reverse().join('');
        if (seen.has(r)) count++;
        seen.add(w);
    }
    return count;
};
